772.answer:
Prim's algorithm builds a minimum spanning tree by starting from an arbitrary node and greedily expanding the MST by always adding the minimum-weight edge that connects a node in the MST to a node outside it. A min-priority queue efficiently retrieves the next cheapest edge. Time complexity: O((V + E) log V) with a binary heap.

```go
package main

import (
	"container/heap"
	"fmt"
)

type Edge struct {
	to, weight int
}

type MinHeap []Edge

func (h MinHeap) Len() int            { return len(h) }
func (h MinHeap) Less(i, j int) bool  { return h[i].weight < h[j].weight }
func (h MinHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *MinHeap) Push(x interface{}) { *h = append(*h, x.(Edge)) }
func (h *MinHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[:n-1]
	return x
}

func primMST(adj [][]Edge, n int) int {
	inMST := make([]bool, n)
	h := &MinHeap{{to: 0, weight: 0}}
	heap.Init(h)
	totalWeight := 0

	for h.Len() > 0 {
		e := heap.Pop(h).(Edge)
		if inMST[e.to] {
			continue
		}
		inMST[e.to] = true
		totalWeight += e.weight
		for _, neighbor := range adj[e.to] {
			if !inMST[neighbor.to] {
				heap.Push(h, neighbor)
			}
		}
	}
	return totalWeight
}

func main() {
	n := 5
	adj := make([][]Edge, n)
	addEdge := func(u, v, w int) {
		adj[u] = append(adj[u], Edge{v, w})
		adj[v] = append(adj[v], Edge{u, w})
	}
	addEdge(0, 1, 2)
	addEdge(0, 3, 6)
	addEdge(1, 2, 3)
	addEdge(1, 3, 8)
	addEdge(1, 4, 5)
	addEdge(2, 4, 7)
	addEdge(3, 4, 9)

	fmt.Println("MST total weight:", primMST(adj, n)) // 16
}
```

773.answer:
Topological sorting produces a linear ordering of vertices in a directed acyclic graph (DAG) such that for every directed edge u -> v, u appears before v. Kahn's algorithm uses in-degree counts: enqueue all nodes with in-degree 0 (no prerequisites), then iteratively process them, decrementing neighbors' in-degrees and enqueuing those that reach 0. If all nodes are processed, the result is valid; otherwise a cycle exists.

```java
import java.util.*;

public class TopologicalSort {
    public static List<Integer> kahnSort(int numNodes, List<int[]> edges) {
        List<List<Integer>> adj = new ArrayList<>();
        int[] inDegree = new int[numNodes];
        for (int i = 0; i < numNodes; i++) adj.add(new ArrayList<>());

        for (int[] e : edges) {
            adj.get(e[0]).add(e[1]);
            inDegree[e[1]]++;
        }

        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < numNodes; i++) {
            if (inDegree[i] == 0) queue.add(i);
        }

        List<Integer> order = new ArrayList<>();
        while (!queue.isEmpty()) {
            int node = queue.poll();
            order.add(node);
            for (int neighbor : adj.get(node)) {
                if (--inDegree[neighbor] == 0) queue.add(neighbor);
            }
        }

        if (order.size() != numNodes) return null; // cycle detected
        return order;
    }

    public static void main(String[] args) {
        List<int[]> edges = Arrays.asList(
            new int[]{5,2}, new int[]{5,0}, new int[]{4,0},
            new int[]{4,1}, new int[]{2,3}, new int[]{3,1}
        );
        System.out.println(kahnSort(6, edges)); // e.g. [4, 5, 0, 2, 3, 1]

        // Cycle test
        List<int[]> cycleEdges = Arrays.asList(
            new int[]{0,1}, new int[]{1,2}, new int[]{2,0}
        );
        System.out.println(kahnSort(3, cycleEdges)); // null
    }
}
```

774.answer:
Cycle detection in a directed graph determines whether there is any path that starts and ends at the same vertex. Using DFS with three-color marking: WHITE (unvisited), GRAY (currently in the DFS stack / being processed), BLACK (fully processed). If during DFS we encounter a GRAY node as a neighbor, we have found a back edge, which means a cycle exists.

```python
from enum import Enum

class Color(Enum):
    WHITE = 0  # unvisited
    GRAY  = 1  # in current DFS stack
    BLACK = 2  # fully processed

def has_cycle(graph: dict[int, list[int]]) -> bool:
    """Returns True if directed graph has a cycle, False otherwise."""
    color = {node: Color.WHITE for node in graph}

    def dfs(u: int) -> bool:
        color[u] = Color.GRAY
        for v in graph.get(u, []):
            if color[v] == Color.GRAY:
                return True   # back edge => cycle
            if color[v] == Color.WHITE and dfs(v):
                return True
        color[u] = Color.BLACK
        return False

    for node in graph:
        if color[node] == Color.WHITE:
            if dfs(node):
                return True
    return False

# Examples
g1 = {0: [1, 2], 1: [2], 2: [3], 3: []}
print(has_cycle(g1))  # False

g2 = {0: [1], 1: [2], 2: [0]}  # 0->1->2->0
print(has_cycle(g2))  # True
```

775.answer:
A trie (prefix tree) is a tree data structure used to store strings where each node represents a character. Nodes on the path from root to a leaf spell out a word. Tries enable efficient prefix-based operations: insert, search, and startsWith all run in O(L) time where L is the word length, making them ideal for autocomplete and dictionary lookups.

```csharp
using System;
using System.Collections.Generic;

public class TrieNode {
    public Dictionary<char, TrieNode> Children = new();
    public bool IsEnd = false;
}

public class Trie {
    private readonly TrieNode _root = new();

    public void Insert(string word) {
        var node = _root;
        foreach (var ch in word) {
            if (!node.Children.ContainsKey(ch))
                node.Children[ch] = new TrieNode();
            node = node.Children[ch];
        }
        node.IsEnd = true;
    }

    public bool Search(string word) {
        var node = _root;
        foreach (var ch in word) {
            if (!node.Children.ContainsKey(ch)) return false;
            node = node.Children[ch];
        }
        return node.IsEnd;
    }

    public bool StartsWith(string prefix) {
        var node = _root;
        foreach (var ch in prefix) {
            if (!node.Children.ContainsKey(ch)) return false;
            node = node.Children[ch];
        }
        return true;
    }
}

class Program {
    static void Main() {
        var trie = new Trie();
        trie.Insert("apple");
        trie.Insert("app");
        Console.WriteLine(trie.Search("apple"));    // True
        Console.WriteLine(trie.Search("app"));      // True
        Console.WriteLine(trie.Search("ap"));       // False
        Console.WriteLine(trie.StartsWith("ap"));   // True
        Console.WriteLine(trie.StartsWith("xyz"));  // False
    }
}
```

776.answer:
A hash table maps keys to values using a hash function that converts a key into an array index. Collisions (multiple keys mapping to the same index) are resolved with separate chaining, where each bucket holds a linked list of entries. Average time complexity for get/put/delete is O(1); worst case O(n) if all keys collide.

```javascript
class HashMap {
  constructor(capacity = 16) {
    this.capacity = capacity;
    this.buckets = Array.from({ length: capacity }, () => []);
    this.size = 0;
  }

  _hash(key) {
    let hash = 0;
    for (let i = 0; i < key.length; i++) {
      hash = (hash * 31 + key.charCodeAt(i)) % this.capacity;
    }
    return hash;
  }

  put(key, value) {
    const idx = this._hash(key);
    const bucket = this.buckets[idx];
    for (const entry of bucket) {
      if (entry[0] === key) { entry[1] = value; return; }
    }
    bucket.push([key, value]);
    this.size++;
  }

  get(key) {
    const bucket = this.buckets[this._hash(key)];
    for (const [k, v] of bucket) {
      if (k === key) return v;
    }
    return undefined;
  }

  remove(key) {
    const idx = this._hash(key);
    const bucket = this.buckets[idx];
    const i = bucket.findIndex(([k]) => k === key);
    if (i !== -1) { bucket.splice(i, 1); this.size--; return true; }
    return false;
  }
}

// Example
const map = new HashMap();
map.put("name", 42);
map.put("age", 30);
console.log(map.get("name")); // 42
console.log(map.get("age"));  // 30
map.remove("age");
console.log(map.get("age"));  // undefined
```

777.answer:
A binary search tree (BST) is a node-based data structure where each node has at most two children, and for every node: all values in the left subtree are smaller, and all values in the right subtree are larger. This property enables efficient search, insertion, and deletion in O(h) time where h is the tree height (O(log n) when balanced). In-order traversal of a BST yields elements in sorted order.

```python
class Node:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

class BST:
    def __init__(self):
        self.root = None

    def insert(self, val):
        def _insert(node, val):
            if node is None:
                return Node(val)
            if val < node.val:
                node.left = _insert(node.left, val)
            elif val > node.val:
                node.right = _insert(node.right, val)
            return node
        self.root = _insert(self.root, val)

    def search(self, val) -> bool:
        def _search(node, val):
            if node is None:
                return False
            if val == node.val:
                return True
            return _search(node.left, val) if val < node.val else _search(node.right, val)
        return _search(self.root, val)

    def inorder(self) -> list:
        result = []
        def _inorder(node):
            if node:
                _inorder(node.left)
                result.append(node.val)
                _inorder(node.right)
        _inorder(self.root)
        return result

# Example
bst = BST()
for v in [5, 3, 7, 1, 4, 6, 8]:
    bst.insert(v)
print(bst.inorder())    # [1, 3, 4, 5, 6, 7, 8]
print(bst.search(4))    # True
print(bst.search(9))    # False
```

778.answer:
An AVL tree is a self-balancing binary search tree where the heights of the two child subtrees of any node differ by at most 1. After each insertion, the tree may become unbalanced and requires up to O(log n) rotations to restore balance. Four cases exist: left-left (right rotation), right-right (left rotation), left-right (left rotate then right rotate), and right-left (right rotate then left rotate). All operations remain O(log n).

```java
public class AVLTree {
    static class Node {
        int val, height;
        Node left, right;
        Node(int v) { val = v; height = 1; }
    }

    private int height(Node n) { return n == null ? 0 : n.height; }
    private int balance(Node n) { return n == null ? 0 : height(n.left) - height(n.right); }
    private void updateHeight(Node n) { n.height = 1 + Math.max(height(n.left), height(n.right)); }

    private Node rotateRight(Node y) {
        Node x = y.left; y.left = x.right; x.right = y;
        updateHeight(y); updateHeight(x); return x;
    }
    private Node rotateLeft(Node x) {
        Node y = x.right; x.right = y.left; y.left = x;
        updateHeight(x); updateHeight(y); return y;
    }

    private Node insert(Node node, int val) {
        if (node == null) return new Node(val);
        if (val < node.val)       node.left  = insert(node.left,  val);
        else if (val > node.val)  node.right = insert(node.right, val);
        else return node; // duplicate
        updateHeight(node);
        int bf = balance(node);
        if (bf > 1 && val < node.left.val)           return rotateRight(node);        // LL
        if (bf < -1 && val > node.right.val)          return rotateLeft(node);         // RR
        if (bf > 1 && val > node.left.val)  { node.left  = rotateLeft(node.left);   return rotateRight(node); } // LR
        if (bf < -1 && val < node.right.val){ node.right = rotateRight(node.right); return rotateLeft(node);  } // RL
        return node;
    }

    Node root;
    public void insert(int val) { root = insert(root, val); }

    public void inorder(Node n) {
        if (n == null) return;
        inorder(n.left);
        System.out.print(n.val + " ");
        inorder(n.right);
    }

    public static void main(String[] args) {
        AVLTree tree = new AVLTree();
        for (int v : new int[]{10, 20, 30, 40, 50, 25}) tree.insert(v);
        tree.inorder(tree.root); // 10 20 25 30 40 50
        System.out.println();
    }
}
```

779.answer:
A heap is a complete binary tree satisfying the heap property: in a min-heap, every parent is less than or equal to its children. The minimum element is always at the root. Heaps are typically stored in arrays (children of index i are at 2i+1 and 2i+2). Insert adds to the end then sifts up; extract-min removes the root, places the last element there, then sifts down. Both operations are O(log n).

```cpp
#include <iostream>
#include <vector>
#include <stdexcept>

class MinHeap {
    std::vector<int> data;

    void siftUp(int i) {
        while (i > 0) {
            int parent = (i - 1) / 2;
            if (data[parent] > data[i]) {
                std::swap(data[parent], data[i]);
                i = parent;
            } else break;
        }
    }

    void siftDown(int i) {
        int n = data.size();
        while (true) {
            int smallest = i, l = 2*i+1, r = 2*i+2;
            if (l < n && data[l] < data[smallest]) smallest = l;
            if (r < n && data[r] < data[smallest]) smallest = r;
            if (smallest == i) break;
            std::swap(data[i], data[smallest]);
            i = smallest;
        }
    }

public:
    void insert(int val) {
        data.push_back(val);
        siftUp(data.size() - 1);
    }

    int getMin() const {
        if (data.empty()) throw std::runtime_error("Heap is empty");
        return data[0];
    }

    int extractMin() {
        if (data.empty()) throw std::runtime_error("Heap is empty");
        int minVal = data[0];
        data[0] = data.back();
        data.pop_back();
        if (!data.empty()) siftDown(0);
        return minVal;
    }

    int size() const { return data.size(); }
};

int main() {
    MinHeap h;
    for (int v : {5, 3, 8, 1, 2, 7}) h.insert(v);
    std::cout << "Min: " << h.getMin() << std::endl; // 1
    while (h.size() > 0)
        std::cout << h.extractMin() << " "; // 1 2 3 5 7 8
    std::cout << std::endl;
    return 0;
}
```

781.answer:
A monotonic queue (deque) maintains elements in decreasing or increasing order from front to back. For the sliding window maximum problem, we keep a deque of indices whose corresponding values are in decreasing order. We remove indices that fall outside the window from the front, and remove from the back any index whose value is less than or equal to the current element (since they can never be the maximum). The front always holds the maximum of the current window. Time complexity: O(n).

```javascript
function slidingWindowMax(nums, k) {
  const deque = []; // stores indices
  const result = [];

  for (let i = 0; i < nums.length; i++) {
    // Remove indices outside the window
    while (deque.length > 0 && deque[0] < i - k + 1) {
      deque.shift();
    }
    // Maintain decreasing order: remove smaller elements from back
    while (deque.length > 0 && nums[deque[deque.length - 1]] <= nums[i]) {
      deque.pop();
    }
    deque.push(i);

    // Window has at least k elements
    if (i >= k - 1) {
      result.push(nums[deque[0]]);
    }
  }
  return result;
}

// Examples
console.log(slidingWindowMax([1,3,-1,-3,5,3,6,7], 3)); // [3,3,5,5,6,7]
console.log(slidingWindowMax([1,2,3,4,5], 2));          // [2,3,4,5]
```

782.answer:
A linked list is a linear data structure where each element (node) stores a value and a pointer to the next node. Unlike arrays, linked lists allow O(1) insertion/deletion at known positions but require O(n) access. Reversing a singly linked list re-links all nodes so they point in the opposite direction.

```go
package main

import "fmt"

type Node struct {
	Val  int
	Next *Node
}

// Iterative reversal
func reverseIterative(head *Node) *Node {
	var prev *Node
	curr := head
	for curr != nil {
		next := curr.Next
		curr.Next = prev
		prev = curr
		curr = next
	}
	return prev
}

// Recursive reversal
func reverseRecursive(head *Node) *Node {
	if head == nil || head.Next == nil {
		return head
	}
	newHead := reverseRecursive(head.Next)
	head.Next.Next = head
	head.Next = nil
	return newHead
}

func toSlice(head *Node) []int {
	var result []int
	for head != nil {
		result = append(result, head.Val)
		head = head.Next
	}
	return result
}

func buildList(vals []int) *Node {
	if len(vals) == 0 { return nil }
	head := &Node{Val: vals[0]}
	curr := head
	for _, v := range vals[1:] {
		curr.Next = &Node{Val: v}
		curr = curr.Next
	}
	return head
}

func main() {
	list1 := buildList([]int{1, 2, 3, 4, 5})
	fmt.Println(toSlice(reverseIterative(list1)))  // [5 4 3 2 1]

	list2 := buildList([]int{1, 2, 3, 4, 5})
	fmt.Println(toSlice(reverseRecursive(list2)))  // [5 4 3 2 1]
}
```

784.answer:
An LRU (Least Recently Used) cache evicts the least recently accessed item when it reaches capacity. To achieve O(1) get and put, we use a hash map for O(1) access by key and a doubly linked list to maintain usage order (most recent at head, least recent at tail). On access or update, the node is moved to the head. On capacity overflow, the tail node is evicted.

```java
import java.util.HashMap;

public class LRUCache {
    private static class Node {
        int key, val;
        Node prev, next;
        Node(int k, int v) { key = k; val = v; }
    }

    private final int capacity;
    private final HashMap<Integer, Node> map = new HashMap<>();
    private final Node head = new Node(0, 0); // dummy head
    private final Node tail = new Node(0, 0); // dummy tail

    public LRUCache(int capacity) {
        this.capacity = capacity;
        head.next = tail;
        tail.prev = head;
    }

    private void remove(Node node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }

    private void insertFront(Node node) {
        node.next = head.next;
        node.prev = head;
        head.next.prev = node;
        head.next = node;
    }

    public int get(int key) {
        if (!map.containsKey(key)) return -1;
        Node node = map.get(key);
        remove(node);
        insertFront(node);
        return node.val;
    }

    public void put(int key, int value) {
        if (map.containsKey(key)) remove(map.get(key));
        Node node = new Node(key, value);
        map.put(key, node);
        insertFront(node);
        if (map.size() > capacity) {
            Node lru = tail.prev;
            remove(lru);
            map.remove(lru.key);
        }
    }

    public static void main(String[] args) {
        LRUCache cache = new LRUCache(2);
        cache.put(1, 1);
        cache.put(2, 2);
        System.out.println(cache.get(1)); // 1
        cache.put(3, 3);                  // evicts key 2
        System.out.println(cache.get(2)); // -1
        cache.put(4, 4);                  // evicts key 1
        System.out.println(cache.get(3)); // 3
        System.out.println(cache.get(4)); // 4
    }
}
```

786.answer:
A mutex (mutual exclusion lock) ensures that only one thread can access a critical section of code at a time, preventing data races. Without a mutex, concurrent increments to a shared counter can produce incorrect results because the read-modify-write sequence is not atomic. std::mutex in C++ provides lock() and unlock() methods; std::lock_guard or std::unique_lock acquire and automatically release the mutex.

```cpp
#include <iostream>
#include <thread>
#include <mutex>
#include <vector>

class ThreadSafeCounter {
    int count = 0;
    std::mutex mtx;
public:
    void increment(int times) {
        for (int i = 0; i < times; i++) {
            std::lock_guard<std::mutex> lock(mtx); // RAII: auto-releases on scope exit
            count++;
        }
    }
    int get() const { return count; }
};

int main() {
    ThreadSafeCounter counter;
    const int numThreads = 10;
    const int incPerThread = 1000;
    std::vector<std::thread> threads;

    for (int i = 0; i < numThreads; i++) {
        threads.emplace_back(&ThreadSafeCounter::increment, &counter, incPerThread);
    }
    for (auto& t : threads) t.join();

    std::cout << "Final count: " << counter.get() << std::endl; // 10000
    return 0;
}
```

787.answer:
A semaphore is a synchronization primitive that controls access to a shared resource by maintaining a count. A counting semaphore with N permits allows at most N threads to be in the critical section simultaneously. acquire() decrements the count (blocking if 0); release() increments it. This is useful for limiting concurrency to a resource pool (e.g., database connection pools).

```java
import java.util.concurrent.Semaphore;

public class ResourcePool {
    private static final int PERMITS = 3;
    private static final Semaphore semaphore = new Semaphore(PERMITS);

    static void accessResource(int threadId) {
        System.out.println("Thread-" + threadId + " waiting for permit...");
        try {
            semaphore.acquire();
            System.out.println("Thread-" + threadId + " acquired permit. Active: " +
                               (PERMITS - semaphore.availablePermits()));
            Thread.sleep(500); // simulate work
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        } finally {
            semaphore.release();
            System.out.println("Thread-" + threadId + " released permit.");
        }
    }

    public static void main(String[] args) throws InterruptedException {
        Thread[] threads = new Thread[7];
        for (int i = 0; i < threads.length; i++) {
            final int id = i;
            threads[i] = new Thread(() -> accessResource(id));
        }
        for (Thread t : threads) t.start();
        for (Thread t : threads) t.join();
        System.out.println("All threads completed.");
    }
}
```

788.answer:
The observer pattern defines a one-to-many dependency: when a subject (publisher) changes state, all registered observers (subscribers) are notified and updated automatically. It decouples the subject from its observers, enabling loose coupling. This is the foundation of event-driven systems and the publish-subscribe model.

```python
from abc import ABC, abstractmethod

# Observer interface
class Observer(ABC):
    @abstractmethod
    def update(self, temperature: float, humidity: float): ...

# Subject
class WeatherStation:
    def __init__(self):
        self._observers: list[Observer] = []
        self._temperature = 0.0
        self._humidity = 0.0

    def subscribe(self, obs: Observer):
        self._observers.append(obs)

    def unsubscribe(self, obs: Observer):
        self._observers.remove(obs)

    def set_measurements(self, temp: float, humidity: float):
        self._temperature = temp
        self._humidity = humidity
        self._notify()

    def _notify(self):
        for obs in self._observers:
            obs.update(self._temperature, self._humidity)

# Concrete observers
class CurrentConditionsDisplay(Observer):
    def update(self, temperature, humidity):
        print(f"[Current Conditions] Temp: {temperature}C, Humidity: {humidity}%")

class StatisticsDisplay(Observer):
    def __init__(self):
        self._readings = []
    def update(self, temperature, humidity):
        self._readings.append(temperature)
        avg = sum(self._readings) / len(self._readings)
        print(f"[Statistics] Avg Temp: {avg:.1f}C")

# Demo
station = WeatherStation()
disp1 = CurrentConditionsDisplay()
disp2 = StatisticsDisplay()
station.subscribe(disp1)
station.subscribe(disp2)
station.set_measurements(22.5, 65)
station.set_measurements(25.0, 70)
station.set_measurements(18.0, 80)
```

789.answer:
The strategy pattern defines a family of algorithms, encapsulates each one, and makes them interchangeable at runtime without changing the client code. It separates the behavior from the object that uses it, enabling Open/Closed Principle compliance. For payment processing, different strategies (credit card, PayPal, bank transfer) can be swapped in the payment context without altering the checkout logic.

```javascript
// Strategy interface (implicitly defined by duck typing in JS)
class CreditCardStrategy {
  pay(amount) {
    console.log(`Paid $${amount} via Credit Card.`);
  }
}

class PayPalStrategy {
  pay(amount) {
    console.log(`Paid $${amount} via PayPal.`);
  }
}

class BankTransferStrategy {
  pay(amount) {
    console.log(`Paid $${amount} via Bank Transfer.`);
  }
}

// Context
class PaymentContext {
  constructor(strategy) {
    this.strategy = strategy;
  }

  setStrategy(strategy) {
    this.strategy = strategy;
  }

  checkout(amount) {
    this.strategy.pay(amount);
  }
}

// Usage
const ctx = new PaymentContext(new CreditCardStrategy());
ctx.checkout(100);  // Paid $100 via Credit Card.

ctx.setStrategy(new PayPalStrategy());
ctx.checkout(250);  // Paid $250 via PayPal.

ctx.setStrategy(new BankTransferStrategy());
ctx.checkout(500);  // Paid $500 via Bank Transfer.
```

790.answer:
The factory method pattern defines an interface for creating objects but lets subclasses or implementations decide which class to instantiate. It encapsulates object creation, enabling new types to be added without changing client code. Notification senders for different channels (email, SMS, push) are a classic example: a factory creates the right sender based on a channel type.

```java
// Product interface
interface NotificationSender {
    void send(String message, String recipient);
}

// Concrete products
class EmailSender implements NotificationSender {
    public void send(String message, String recipient) {
        System.out.println("Email to " + recipient + ": " + message);
    }
}

class SmsSender implements NotificationSender {
    public void send(String message, String recipient) {
        System.out.println("SMS to " + recipient + ": " + message);
    }
}

class PushSender implements NotificationSender {
    public void send(String message, String recipient) {
        System.out.println("Push to " + recipient + ": " + message);
    }
}

// Factory
class NotificationFactory {
    public static NotificationSender create(String channel) {
        return switch (channel.toLowerCase()) {
            case "email" -> new EmailSender();
            case "sms"   -> new SmsSender();
            case "push"  -> new PushSender();
            default -> throw new IllegalArgumentException("Unknown channel: " + channel);
        };
    }
}

// Client
public class FactoryMethodDemo {
    public static void main(String[] args) {
        for (String channel : new String[]{"email", "sms", "push"}) {
            NotificationSender sender = NotificationFactory.create(channel);
            sender.send("Hello!", "user@example.com");
        }
    }
}
```

791.answer:
The singleton pattern ensures a class has only one instance and provides a global access point to it. In multi-threaded environments, naive singletons can create multiple instances if two threads simultaneously check-and-create. A thread-safe implementation can use a static initializer (guaranteed by the CLR in C#), Lazy<T>, or double-checked locking. Lazy<T> is the idiomatic, thread-safe C# approach.

```csharp
using System;
using System.Threading;

public sealed class Logger {
    // Lazy<T> is thread-safe by default (LazyThreadSafetyMode.ExecutionAndPublication)
    private static readonly Lazy<Logger> _instance =
        new Lazy<Logger>(() => new Logger());

    private Logger() {
        Console.WriteLine("Logger instance created.");
    }

    public static Logger Instance => _instance.Value;

    public void Log(string message) {
        Console.WriteLine($"[{DateTime.Now:HH:mm:ss}] {message}");
    }
}

class Program {
    static void Main() {
        // Multiple threads accessing Logger concurrently
        Thread[] threads = new Thread[5];
        for (int i = 0; i < threads.Length; i++) {
            int id = i;
            threads[i] = new Thread(() => {
                Logger.Instance.Log($"Message from thread {id}");
            });
        }
        foreach (var t in threads) t.Start();
        foreach (var t in threads) t.Join();
        // "Logger instance created." appears exactly once
    }
}
```

792.answer:
The decorator pattern attaches additional responsibilities to an object dynamically without modifying its class. Decorators wrap the original component and implement the same interface, forwarding calls to the wrapped object while adding behavior before or after. This is more flexible than subclassing because behaviors can be combined in any order at runtime.

```python
from abc import ABC, abstractmethod

# Component interface
class TextComponent(ABC):
    @abstractmethod
    def render(self) -> str: ...

# Concrete component
class PlainText(TextComponent):
    def __init__(self, text: str):
        self._text = text
    def render(self) -> str:
        return self._text

# Base decorator
class TextDecorator(TextComponent):
    def __init__(self, component: TextComponent):
        self._component = component
    def render(self) -> str:
        return self._component.render()

# Concrete decorators
class BoldDecorator(TextDecorator):
    def render(self) -> str:
        return f"<b>{self._component.render()}</b>"

class ItalicDecorator(TextDecorator):
    def render(self) -> str:
        return f"<i>{self._component.render()}</i>"

# Demo
text = PlainText("Hello, World")
bold_text = BoldDecorator(text)
bold_italic_text = ItalicDecorator(bold_text)

print(text.render())              # Hello, World
print(bold_text.render())         # <b>Hello, World</b>
print(bold_italic_text.render())  # <i><b>Hello, World</b></i>

# Decorators can be composed in any order
italic_bold = BoldDecorator(ItalicDecorator(PlainText("Test")))
print(italic_bold.render())       # <b><i>Test</i></b>
```

793.answer:
The adapter pattern converts one interface into another that a client expects. It acts as a bridge between incompatible interfaces without modifying existing code. A class adapter wraps the adaptee and implements the target interface. This is useful when integrating legacy systems with new interfaces—for example, adapting an XML-based service to a JSON-based interface.

```typescript
// Target interface expected by clients
interface JsonDataService {
  getData(id: string): Record<string, unknown>;
}

// Legacy XML service (the Adaptee)
class LegacyXmlService {
  fetchXml(id: string): string {
    return `<data><id>${id}</id><value>legacy-value-${id}</value></data>`;
  }

  parseXml(xml: string): { id: string; value: string } {
    const id    = xml.match(/<id>(.*?)<\/id>/)![1];
    const value = xml.match(/<value>(.*?)<\/value>/)![1];
    return { id, value };
  }
}

// Adapter: wraps LegacyXmlService, exposes JsonDataService interface
class XmlToJsonAdapter implements JsonDataService {
  private xmlService: LegacyXmlService;

  constructor() {
    this.xmlService = new LegacyXmlService();
  }

  getData(id: string): Record<string, unknown> {
    const xml    = this.xmlService.fetchXml(id);
    const parsed = this.xmlService.parseXml(xml);
    // Convert to JSON-compatible format
    return { id: parsed.id, value: parsed.value, source: "xml-adapter" };
  }
}

// Client code - only knows about JsonDataService
function displayData(service: JsonDataService, id: string): void {
  const data = service.getData(id);
  console.log(JSON.stringify(data, null, 2));
}

const adapter = new XmlToJsonAdapter();
displayData(adapter, "42");
// { "id": "42", "value": "legacy-value-42", "source": "xml-adapter" }
```

794.answer:
The command pattern encapsulates a request as an object, allowing parameterization of clients with different requests, queuing/logging requests, and supporting undoable operations. Each command implements an execute() method and optionally an undo() method. An invoker stores a history of commands, enabling undo by calling undo() on the most recent command.

```javascript
// Receiver
class Light {
  constructor(location) {
    this.location = location;
    this.on = false;
  }
  turnOn()  { this.on = true;  console.log(`${this.location} light ON`);  }
  turnOff() { this.on = false; console.log(`${this.location} light OFF`); }
}

// Commands
class LightOnCommand {
  constructor(light) { this.light = light; }
  execute() { this.light.turnOn(); }
  undo()    { this.light.turnOff(); }
}

class LightOffCommand {
  constructor(light) { this.light = light; }
  execute() { this.light.turnOff(); }
  undo()    { this.light.turnOn(); }
}

// Invoker with undo support
class RemoteControl {
  constructor() { this.history = []; }

  press(command) {
    command.execute();
    this.history.push(command);
  }

  undoLast() {
    if (this.history.length === 0) { console.log("Nothing to undo"); return; }
    const last = this.history.pop();
    last.undo();
  }
}

// Demo
const livingRoomLight = new Light("Living Room");
const remote = new RemoteControl();

remote.press(new LightOnCommand(livingRoomLight));   // Living Room light ON
remote.press(new LightOffCommand(livingRoomLight));  // Living Room light OFF
remote.undoLast();                                   // Living Room light ON (undo OFF)
remote.undoLast();                                   // Living Room light OFF (undo ON)
```

795.answer:
The state pattern allows an object to alter its behavior when its internal state changes, appearing to change its class. Instead of large if/else or switch statements, each state is encapsulated in a class implementing a common interface. The context delegates state-specific behavior to the current state object. This is ideal for state machines like vending machines.

```java
// State interface
interface VendingMachineState {
    void insertCoin(VendingMachine machine);
    void selectProduct(VendingMachine machine);
    void dispense(VendingMachine machine);
}

// Concrete states
class IdleState implements VendingMachineState {
    public void insertCoin(VendingMachine m) {
        System.out.println("Coin inserted.");
        m.setState(m.getHasCoinState());
    }
    public void selectProduct(VendingMachine m) { System.out.println("Please insert coin first."); }
    public void dispense(VendingMachine m)       { System.out.println("Please insert coin first."); }
}

class HasCoinState implements VendingMachineState {
    public void insertCoin(VendingMachine m) { System.out.println("Coin already inserted."); }
    public void selectProduct(VendingMachine m) {
        System.out.println("Product selected.");
        m.setState(m.getDispensingState());
    }
    public void dispense(VendingMachine m) { System.out.println("Select a product first."); }
}

class DispensingState implements VendingMachineState {
    public void insertCoin(VendingMachine m) { System.out.println("Dispensing, please wait."); }
    public void selectProduct(VendingMachine m) { System.out.println("Dispensing, please wait."); }
    public void dispense(VendingMachine m) {
        System.out.println("Product dispensed!");
        m.setState(m.getIdleState());
    }
}

// Context
class VendingMachine {
    private VendingMachineState idleState    = new IdleState();
    private VendingMachineState hasCoinState = new HasCoinState();
    private VendingMachineState dispensingState = new DispensingState();
    private VendingMachineState currentState  = idleState;

    public void setState(VendingMachineState s) { this.currentState = s; }
    public VendingMachineState getIdleState()       { return idleState; }
    public VendingMachineState getHasCoinState()    { return hasCoinState; }
    public VendingMachineState getDispensingState() { return dispensingState; }

    public void insertCoin()    { currentState.insertCoin(this); }
    public void selectProduct() { currentState.selectProduct(this); }
    public void dispense()      { currentState.dispense(this); }
}

class StatePatternDemo {
    public static void main(String[] args) {
        VendingMachine machine = new VendingMachine();
        machine.selectProduct(); // Please insert coin first.
        machine.insertCoin();    // Coin inserted.
        machine.selectProduct(); // Product selected.
        machine.dispense();      // Product dispensed!
        machine.dispense();      // Please insert coin first.
    }
}
```

796.answer:
The template method pattern defines the skeleton of an algorithm in a base class, deferring certain steps to subclasses. The base class calls abstract methods at specific points; subclasses provide concrete implementations without changing the overall algorithm structure. This avoids code duplication while allowing variation in specific steps.

```csharp
using System;

// Abstract class with template method
abstract class DataParser {
    // Template method - defines the algorithm skeleton
    public void ParseFile(string data) {
        Console.WriteLine($"--- Starting {GetFormatName()} parsing ---");
        string[] lines = ReadLines(data);
        var records = ProcessLines(lines);
        PrintResults(records);
    }

    protected abstract string GetFormatName();
    protected abstract string[] ReadLines(string data);
    protected abstract string[] ProcessLines(string[] lines);

    // Hook with default behavior
    protected virtual void PrintResults(string[] records) {
        Console.WriteLine($"Parsed {records.Length} record(s):");
        foreach (var r in records) Console.WriteLine("  " + r);
    }
}

// CSV subclass
class CsvParser : DataParser {
    protected override string GetFormatName() => "CSV";
    protected override string[] ReadLines(string data) => data.Split('\n');
    protected override string[] ProcessLines(string[] lines) {
        return Array.ConvertAll(lines, l => string.Join(" | ", l.Split(',')));
    }
}

// JSON subclass (simplified)
class JsonParser : DataParser {
    protected override string GetFormatName() => "JSON";
    protected override string[] ReadLines(string data) =>
        data.Trim('{', '}').Split(',');
    protected override string[] ProcessLines(string[] lines) {
        return Array.ConvertAll(lines, l => l.Trim().Replace('"', ' ').Trim());
    }
}

class TemplateMethodDemo {
    static void Main() {
        new CsvParser().ParseFile("Alice,30,Engineer\nBob,25,Designer");
        new JsonParser().ParseFile("{\"name\":\"Carol\",\"age\":28}");
    }
}
```

797.answer:
The repository pattern abstracts the data layer by providing a collection-like interface for accessing domain objects. Client code works with the repository interface, unaware of whether data comes from a database, API, or in-memory store. This decouples business logic from data access, making it easy to swap persistence strategies and simplify testing with in-memory repositories.

```python
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class User:
    id: int
    name: str
    email: str

# Repository interface
class UserRepository(ABC):
    @abstractmethod
    def add(self, user: User) -> None: ...
    @abstractmethod
    def get_by_id(self, user_id: int) -> Optional[User]: ...
    @abstractmethod
    def list_all(self) -> list[User]: ...

# In-memory implementation
class InMemoryUserRepository(UserRepository):
    def __init__(self):
        self._store: dict[int, User] = {}

    def add(self, user: User) -> None:
        if user.id in self._store:
            raise ValueError(f"User {user.id} already exists")
        self._store[user.id] = user

    def get_by_id(self, user_id: int) -> Optional[User]:
        return self._store.get(user_id)

    def list_all(self) -> list[User]:
        return list(self._store.values())

# Demo
repo = InMemoryUserRepository()
repo.add(User(1, "Alice", "alice@example.com"))
repo.add(User(2, "Bob",   "bob@example.com"))
repo.add(User(3, "Carol", "carol@example.com"))

print(repo.get_by_id(2))   # User(id=2, name='Bob', email='bob@example.com')
print(repo.get_by_id(99))  # None
for user in repo.list_all():
    print(user)
```

798.answer:
Middleware chaining is a design pattern where a request passes sequentially through a chain of handlers (middleware functions), each of which can inspect or modify the request/response, decide to pass control to the next handler via a next() call, or short-circuit the chain (e.g., reject an unauthenticated request). It is central to frameworks like Express.js. Each middleware has a single responsibility, making the chain composable and testable.

```javascript
// Minimal middleware chaining implementation (Express-like)
function createApp() {
  const middlewares = [];

  function use(fn) {
    middlewares.push(fn);
  }

  function handle(req) {
    let index = 0;
    function next() {
      if (index >= middlewares.length) return;
      const mw = middlewares[index++];
      mw(req, next);
    }
    next();
  }

  return { use, handle };
}

// Middleware functions
function loggingMiddleware(req, next) {
  console.log(`[Logger] ${req.method} ${req.path}`);
  next();
}

function authMiddleware(req, next) {
  if (!req.headers || !req.headers.token) {
    console.log("[Auth] Unauthorized - request rejected");
    return; // short-circuit
  }
  console.log("[Auth] Token valid, proceeding");
  next();
}

function handlerMiddleware(req, next) {
  console.log(`[Handler] Processing ${req.path} - sending response`);
}

// Wire up the app
const app = createApp();
app.use(loggingMiddleware);
app.use(authMiddleware);
app.use(handlerMiddleware);

console.log("=== Authorized Request ===");
app.handle({ method: "GET", path: "/api/data", headers: { token: "secret123" } });

console.log("\n=== Unauthorized Request ===");
app.handle({ method: "POST", path: "/api/data", headers: {} });
```

799.answer:
Rate limiting controls how frequently clients can make requests. The token bucket algorithm maintains a 'bucket' with a maximum capacity of tokens. Tokens are added at a fixed refill rate; each request consumes one token. If the bucket has tokens, the request is allowed; otherwise it is rejected. This allows short bursts (up to bucket capacity) while enforcing an average rate over time.

```go
package main

import (
	"fmt"
	"sync"
	"time"
)

type TokenBucket struct {
	capacity    float64
	tokens      float64
	refillRate  float64 // tokens per second
	lastRefill  time.Time
	mu          sync.Mutex
}

func NewTokenBucket(capacity, refillRate float64) *TokenBucket {
	return &TokenBucket{
		capacity:   capacity,
		tokens:     capacity, // start full
		refillRate: refillRate,
		lastRefill: time.Now(),
	}
}

func (tb *TokenBucket) Allow() bool {
	tb.mu.Lock()
	defer tb.mu.Unlock()

	// Refill tokens based on elapsed time
	now := time.Now()
	elapsed := now.Sub(tb.lastRefill).Seconds()
	tb.tokens += elapsed * tb.refillRate
	if tb.tokens > tb.capacity {
		tb.tokens = tb.capacity
	}
	tb.lastRefill = now

	if tb.tokens >= 1.0 {
		tb.tokens--
		return true // allowed
	}
	return false // rejected
}

func main() {
	// Capacity: 5 tokens, refill rate: 2 tokens/second
	bucket := NewTokenBucket(5, 2)

	for i := 0; i < 8; i++ {
		if bucket.Allow() {
			fmt.Printf("Request %d: ALLOWED\n", i+1)
		} else {
			fmt.Printf("Request %d: REJECTED\n", i+1)
		}
	}

	fmt.Println("Waiting 1 second for refill...")
	time.Sleep(1 * time.Second)

	for i := 0; i < 3; i++ {
		if bucket.Allow() {
			fmt.Printf("Post-wait request %d: ALLOWED\n", i+1)
		} else {
			fmt.Printf("Post-wait request %d: REJECTED\n", i+1)
		}
	}
}
```

800.answer:
Consistent hashing maps both data keys and servers to positions on a circular hash ring (0 to 2^32-1). To find which server a key belongs to, hash the key and walk clockwise until reaching the first server. Adding or removing a server only affects the keys between the removed node and its predecessor, minimizing remapping. Virtual nodes (replicas per server) improve load distribution by placing each server at multiple positions on the ring.

```python
import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, nodes=None, virtual_nodes=150):
        self.virtual_nodes = virtual_nodes
        self.ring = {}       # hash_pos -> node name
        self.sorted_keys = [] # sorted list of hash positions

        if nodes:
            for node in nodes:
                self.add_node(node)

    def _hash(self, key: str) -> int:
        return int(hashlib.md5(key.encode()).hexdigest(), 16)

    def add_node(self, node: str):
        for i in range(self.virtual_nodes):
            vkey = f"{node}#vn{i}"
            pos = self._hash(vkey)
            self.ring[pos] = node
            bisect.insort(self.sorted_keys, pos)

    def remove_node(self, node: str):
        for i in range(self.virtual_nodes):
            vkey = f"{node}#vn{i}"
            pos = self._hash(vkey)
            del self.ring[pos]
            idx = bisect.bisect_left(self.sorted_keys, pos)
            self.sorted_keys.pop(idx)

    def get_node(self, key: str) -> str:
        if not self.ring:
            raise RuntimeError("No nodes in ring")
        pos = self._hash(key)
        idx = bisect.bisect(self.sorted_keys, pos) % len(self.sorted_keys)
        return self.ring[self.sorted_keys[idx]]

# Demo
ring = ConsistentHashRing(nodes=["server-A", "server-B", "server-C"], virtual_nodes=100)

keys = ["user:1", "user:2", "product:99", "session:abc", "cache:xyz"]
for k in keys:
    print(f"{k} -> {ring.get_node(k)}")

print("\nRemoving server-B...")
ring.remove_node("server-B")
for k in keys:
    print(f"{k} -> {ring.get_node(k)}")
```
